mapper.update:
UPDATE interior
SET    i_text = #{i_text}
WHERE  c_id = #{c_id}
       AND c_kind = #{c_kind}
       AND c_name = #{c_name}
       AND i_tag = #{i_tag}

UPDATE i_example
SET    ie_content = #{ie_content}
WHERE  c_id = #{c_id}
       AND c_kind = #{c_kind}
       AND c_name = #{c_name}
       AND ie_tag = #{ie_tag}
       AND ie_tag2 = #{ie_tag2}

UPDATE booking
SET    b_kind = #{b_kind},
       b_long = #{b_long},
       b_status = #{b_status},
       b_date = #{b_date},
       b_content = #{b_content}
WHERE  c_id = #{c_id}
       AND c_kind = #{c_kind}
       AND c_name = #{c_name}
       AND b_createddate = #{b_createdDate}
       AND id = #{id}

UPDATE i_review
SET    ir_content = #{ir_content}
WHERE  c_id = #{c_id}
       AND c_kind = #{c_kind}
       AND c_name = #{c_name}
       AND b_createddate = #{b_createdDate}
       AND id = #{id}

